# tests/rag/test_retrieval.py
import pytest
from app.retrieval import retrieve

K = 5

def recall_at_k(retrieved_ids, relevant_ids, k):
    top_k = retrieved_ids[:k]
    return len(set(top_k) & set(relevant_ids)) / len(relevant_ids)

def reciprocal_rank(retrieved_ids, relevant_ids):
    for rank, doc_id in enumerate(retrieved_ids, 1):
        if doc_id in relevant_ids:
            return 1.0 / rank
    return 0.0

def test_recall_at_5(rag_golden):
    scores = []
    for case in rag_golden:
        result = retrieve(case["question"], k=K)
        retrieved_ids = [doc.id for doc in result.docs]
        scores.append(recall_at_k(retrieved_ids, case["relevant_doc_ids"], K))
    avg = sum(scores) / len(scores)
    assert avg >= 0.75, f"Recall@5={avg:.3f} below threshold"

def test_mrr(rag_golden):
    rr = []
    for case in rag_golden:
        result = retrieve(case["question"], k=K)
        retrieved_ids = [doc.id for doc in result.docs]
        rr.append(reciprocal_rank(retrieved_ids, case["relevant_doc_ids"]))
    assert sum(rr) / len(rr) >= 0.55, "MRR below 0.55"

# tests/rag/test_context_quality.py
from app.pipeline import build_context

MAX_CONTEXT_TOKENS = 3000
NOISE_RATIO_LIMIT = 0.30  # at most 30 % irrelevant chunks

def test_context_token_budget(rag_golden):
    """Assembled context must fit within the model's window budget."""
    for case in rag_golden:
        ctx = build_context(case["question"])
        assert ctx.token_count <= MAX_CONTEXT_TOKENS, (
            f"Context too large ({ctx.token_count}) for: {case['question'][:60]}"
        )

def test_noise_ratio(rag_golden):
    """No more than 30 % of context chunks should be irrelevant."""
    for case in rag_golden:
        ctx = build_context(case["question"])
        irrelevant = [
            c for c in ctx.chunks
            if c.doc_id not in case["relevant_doc_ids"]
        ]
        ratio = len(irrelevant) / max(len(ctx.chunks), 1)
        assert ratio <= NOISE_RATIO_LIMIT, (
            f"Noise {ratio:.0%} exceeds {NOISE_RATIO_LIMIT:.0%}"
        )

# tests/rag/test_e2e.py
import pytest, json
from anthropic import Anthropic
from app.pipeline import rag_pipeline

client = Anthropic()

JUDGE_PROMPT = """
You are a strict evaluator. Score the answer 0 or 1 for each criterion.
Return JSON: {"grounded": 0|1, "correct": 0|1, "no_hallucination": 0|1}

Question: {question}
Context provided to the model:
{context}
Model answer: {answer}
"""

def judge(question, context, answer):
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=128,
        messages=[{"role": "user", "content": JUDGE_PROMPT.format(
            question=question, context=context, answer=answer)}]
    )
    return json.loads(resp.content[0].text)

@pytest.mark.llmjudge
def test_e2e_grounding(rag_golden):
    scores = {"grounded": [], "correct": [], "no_hallucination": []}
    for case in rag_golden:
        result = rag_pipeline(case["question"])
        ctx_text = "\n".join(c.text for c in result.context_chunks)
        verdict = judge(case["question"], ctx_text, result.answer)
        for k in scores:
            scores[k].append(verdict[k])

    assert sum(scores["grounded"]) / len(scores["grounded"]) >= 0.90
    assert sum(scores["correct"]) / len(scores["correct"]) >= 0.80
    assert sum(scores["no_hallucination"]) / len(scores["no_hallucination"]) >= 0.90
